64	async function mockSmokeGraphQL(
65		page: import('@playwright/test').Page,
66		beadCount: number,
67		ids: { nodeId: string; projectId: string; nodeName: string; projectName: string; projectPath: string }
68	) {
69		const beads = generateBeads(beadCount);
70		const nodeInfo = { id: ids.nodeId, name: ids.nodeName };
71		const projects = [{ id: ids.projectId, name: ids.projectName, path: ids.projectPath }];
72		await page.route('/graphql', async (route) => {
73			const body = route.request().postDataJSON() as { query: string };
74			if (body.query.includes('beadsByProject')) {
75				await route.fulfill({
76					status: 200,
77					contentType: 'application/json',
78					body: JSON.stringify({
79						data: {
80							beadsByProject: {
81								edges: beads.map((b, i) => ({ node: b, cursor: `cursor-${i}` })),
82								pageInfo: { hasNextPage: false, endCursor: null },
83								totalCount: beads.length
84							}
85						}
86					})
87				});
88			} else if (body.query.includes('beads(')) {
89				// Cross-project list fetches the `beads` field.
90				await route.fulfill({
91					status: 200,
92					contentType: 'application/json',
93					body: JSON.stringify({
94						data: {
95							beads: {
96								edges: beads.map((b, i) => ({ node: b, cursor: `cursor-${i}` })),
97								pageInfo: { hasNextPage: false, endCursor: null },
98								totalCount: beads.length
99							},
100							projects: { edges: projects.map((p) => ({ node: p })) }
101						}
102					})
103				});
104			} else if (body.query.includes('nodeInfo')) {
105				await route.fulfill({
106					status: 200,
107					contentType: 'application/json',
108					body: JSON.stringify({ data: { nodeInfo } })
109				});
110			} else if (body.query.includes('projects')) {
111				await route.fulfill({
112					status: 200,
113					contentType: 'application/json',
114					body: JSON.stringify({
115						data: { projects: { edges: projects.map((p) => ({ node: p })) } }
116					})
117				});
118			} else {
119				await route.continue();
120			}
121		});
122	}
